  float block[BLOCK_SIZE];
  for (int i = 0; i < BLOCK_SIZE; i++) {
    block[i] = noise_power * gaussZiggurat(0, 1);
  }
  // Write block to noise vector
  memcpy(state.noise + write_block_index * BLOCK_SIZE, block, sizeof(block));
}

